 3→function compileShader(gl: WebGL2RenderingContext, type: number, src: string): WebGLShader | null {
 4→  const s = gl.createShader(type)!;
 5→  gl.shaderSource(s, src);
 6→  gl.compileShader(s);
 7→  if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
 8→    console.error('Shader:', gl.getShaderInfoLog(s));
 9→    gl.deleteShader(s);
10→    return null;
11→  }
12→  return s;
13→}
14→
15→function createProgram(gl: WebGL2RenderingContext, vsSrc: string, fsSrc: string): WebGLProgram | null {
16→  const vs = compileShader(gl, gl.VERTEX_SHADER, vsSrc);
17→  const fs = compileShader(gl, gl.FRAGMENT_SHADER, fsSrc);
18→  if (!vs || !fs) return null;
19→  const p = gl.createProgram()!;
20→  gl.attachShader(p, vs);
21→  gl.attachShader(p, fs);
22→  gl.linkProgram(p);
23→  if (!gl.getProgramParameter(p, gl.LINK_STATUS)) {
24→    console.error('Program:', gl.getProgramInfoLog(p));
25→    return null;
26→  }
27→  return p;
28→}
